            "width": FRAME_WIDTH - 2,
            "axis_config": {
                "include_tip": True,
                "numbers_to_exclude": [0],
            },
            "x_axis_config": {
                # see manimlib/mobjects/number_line.py
                "line_to_number_buff": 0.5,
